45	// FirstParentChainFromMap walks a first-parent map from tip back to root.
46	// The map key is a commit hash, the value is its first parent hash.
47	// A zero-value parent marks the root. Returns the chain in root-to-tip order.
48	func FirstParentChainFromMap(parents map[plumbing.Hash]plumbing.Hash, tip plumbing.Hash) ([]plumbing.Hash, error) {
49		chain := make([]plumbing.Hash, 0, len(parents))
50		current := tip
51		seen := make(map[plumbing.Hash]struct{}, len(parents))
52		for {
53			if _, ok := seen[current]; ok {
54				return nil, fmt.Errorf("cycle detected at %s", current)
55			}
56			seen[current] = struct{}{}
57			chain = append(chain, current)
58			parent, ok := parents[current]
59			if !ok {
60				return nil, fmt.Errorf("commit %s not found in parent map", current)
61			}
62			if parent.IsZero() {
63				break
64			}
65			current = parent
66		}
67		for i, j := 0, len(chain)-1; i < j; i, j = i+1, j-1 {
68			chain[i], chain[j] = chain[j], chain[i]
69		}
70		return chain, nil
71	}
