73	// SampledCheckpointCandidates generates a set of candidate indices to probe,
74	// sorted from largest (preferred) to smallest.
75	func SampledCheckpointCandidates(lo, hi int, prevSpan int) []int {
76		if lo > hi {
77			return nil
78		}
79		set := map[int]struct{}{}
80		add := func(idx int) {
81			if idx < lo {
82				idx = lo
83			}
84			if idx > hi {
85				idx = hi
86			}
87			set[idx] = struct{}{}
88		}
89	
90		projected := hi
91		if prevSpan > 0 {
92			projected = lo + prevSpan - 1
93		}
94		add(projected)
95	
96		const sampleCount = 4
97		current := projected
98		for i := 0; i < sampleCount-1; i++ {
99			if current <= lo {
100				add(lo)
101				continue
102			}
103			distance := current - lo
104			current = lo + distance/2
105			add(current)
106		}
107		add(lo)
108	
109		candidates := make([]int, 0, len(set))
110		for idx := range set {
111			candidates = append(candidates, idx)
112		}
113		sort.Sort(sort.Reverse(sort.IntSlice(candidates)))
114		return candidates
115	}
