117	// SampledCheckpointUnderLimit finds the largest checkpoint index that fits within
118	// the batch limit, using a sampling strategy to reduce probes (issue #14).
119	func SampledCheckpointUnderLimit(
120		chain []plumbing.Hash,
121		prevIdx int,
122		prevSpan int,
123		probe func(idx int) (tooLarge bool, err error),
124	) (int, error) {
125		lo := prevIdx + 1
126		hi := len(chain) - 1
127		if lo > hi {
128			return -1, nil
129		}
130	
131		samples := SampledCheckpointCandidates(lo, hi, prevSpan)
132		best := -1
133		for _, idx := range samples {
134			tooLarge, err := probe(idx)
135			if err != nil {
136				return -1, err
137			}
138			if tooLarge {
139				continue
140			}
141			best = idx
142			break
143		}
144		if best != -1 {
145			return best, nil
146		}
147	
148		if prevSpan > 1 {
149			shrunk := prevSpan / 2
150			if shrunk < 1 {
151				shrunk = 1
152			}
153			idx := lo + shrunk - 1
154			if idx > hi {
155				idx = hi
156			}
157			if idx >= lo {
158				tooLarge, err := probe(idx)
159				if err != nil {
160					return -1, err
161				}
162				if !tooLarge {
163					return idx, nil
164				}
165			}
166		}
167	
168		tooLarge, err := probe(lo)
169		if err != nil {
170			return -1, err
171		}
172		if tooLarge {
173			return -1, nil
174		}
175		return lo, nil
176	}
