178	// BootstrapResumeIndex finds the starting index in a checkpoint list given a resume hash.
179	func BootstrapResumeIndex(checkpoints []plumbing.Hash, resumeHash plumbing.Hash) (int, error) {
180		if resumeHash.IsZero() {
181			return 0, nil
182		}
183		for idx, checkpoint := range checkpoints {
184			if checkpoint == resumeHash {
185				return idx + 1, nil
186			}
187		}
188		return 0, fmt.Errorf("temp ref hash %s does not match any planned checkpoint", resumeHash)
