32	func ListSourceRefs(ctx context.Context, conn *Conn, protocolMode string, refPrefixes []string) ([]*plumbing.Reference, *RefService, error) {
33		switch protocolMode {
34		case "v1":
35			adv, refs, err := listSourceRefsV1(ctx, conn)
36			if err != nil {
37				return nil, nil, err
38			}
39			return refs, &RefService{Protocol: "v1", V1Adv: adv}, nil
40	
41		case "auto", "v2":
42			data, err := RequestInfoRefs(ctx, conn, transport.UploadPackService, "version=2")
43			if err != nil {
44				return nil, nil, err
45			}
46			if caps, err := DecodeV2Capabilities(bytes.NewReader(data)); err == nil {
