105	func AdvRefsCaps(adv *packp.AdvRefs) []string {
106		if adv == nil || adv.Capabilities == nil {
107			return nil
108		}
109		all := adv.Capabilities.All()
110		items := make([]string, 0, len(all))
111		for _, cap := range all {
112			values := adv.Capabilities.Get(cap)
113			if len(values) == 0 {
114				items = append(items, string(cap))
115				continue
116			}
117			for _, value := range values {
118				items = append(items, string(cap)+"="+value)
119			}
120		}
121		return items
