136	func listSourceRefsV2(ctx context.Context, conn *Conn, caps *V2Capabilities, prefixes []string) ([]*plumbing.Reference, error) {
137		args := []string{"peel"}
138		for _, prefix := range prefixes {
139			args = append(args, "ref-prefix "+prefix)
140		}
141		body, err := EncodeCommand("ls-refs", caps.RequestCapabilities(), args)
142		if err != nil {
143			return nil, err
144		}
145		data, err := PostRPC(ctx, conn, transport.UploadPackService, body, true, "upload-pack ls-refs")
146		if err != nil {
