152	func decodeV2LSRefs(r *bytes.Reader) ([]*plumbing.Reference, error) {
153		reader := NewPacketReader(r)
154		var refs []*plumbing.Reference
155		for {
156			kind, payload, err := reader.ReadPacket()
157			if err != nil {
158				return nil, err
159			}
160			if kind == PacketFlush {
161				return refs, nil
162			}
163			if kind != PacketData {
164				return nil, fmt.Errorf("unexpected packet type %v in ls-refs response", kind)
165			}
166			fields := strings.Fields(strings.TrimSpace(string(payload)))
167			if len(fields) < 2 {
168				return nil, fmt.Errorf("malformed ls-refs response line %q", payload)
169			}
170			hash := plumbing.NewHash(fields[0])
171			name := plumbing.ReferenceName(fields[1])
172			refs = append(refs, plumbing.NewHashReference(name, hash))
173		}
174	}
