176	func decodeV1AdvRefs(data []byte) (*packp.AdvRefs, error) {
177		rd := bufio.NewReader(bytes.NewReader(data))
178		consumedSmartHeader, err := consumeSmartInfoRefsHeader(rd)
179		if err != nil {
180			return nil, fmt.Errorf("%w; body-prefix=%q", err, bodyPreview(data))
181		}
182		if consumedSmartHeader {
183			if _, err := rd.Peek(1); errors.Is(err, io.EOF) {
184				return nil, transport.ErrEmptyRemoteRepository
185			}
186		}
187	
188		ar := packp.NewAdvRefs()
189		if err := ar.Decode(rd); err != nil {
190			if err == packp.ErrEmptyAdvRefs {
191				return nil, transport.ErrEmptyRemoteRepository
192			}
193			return nil, fmt.Errorf("%w; body-prefix=%q", err, bodyPreview(data))
194		}
195		return ar, nil
196	}
197	
198	func consumeSmartInfoRefsHeader(rd *bufio.Reader) (bool, error) {
199		_, prefix, err := pktline.PeekLine(rd)
200		if err != nil {
201			return false, err
202		}
203		if !bytes.HasPrefix(prefix, []byte("# service=")) {
204			return false, nil
205		}
206	
207		var reply packp.SmartReply
208		if err := reply.Decode(rd); err != nil {
209			return true, err
210		}
211		if reply.Service == "" {
212			return true, errors.New("missing smart HTTP service name")
213		}
214		return true, nil
215	}
