217	func bodyPreview(data []byte) string {
218		if len(data) == 0 {
219			return ""
220		}
221		limit := 200
222		if len(data) < limit {
223			limit = len(data)
224		}
225		preview := string(data[:limit])
226		preview = strings.ReplaceAll(preview, "\n", `\n`)
227		preview = strings.ReplaceAll(preview, "\r", `\r`)
228		if len(data) > limit {
229			preview += "..."
230		}
231		return preview
232	}
