349	func newSession(ctx context.Context, cfg Config, needTarget bool) (*syncSession, error) {
350		mode, err := validation.NormalizeProtocolMode(cfg.ProtocolMode)
351		if err != nil {
352			return nil, err
353		}
354		cfg.ProtocolMode = mode
355		switch cfg.Mode {
356		case "", modeSync:
357			cfg.Mode = modeSync
358		case modeReplicate:
359		default:
360			return nil, fmt.Errorf("unsupported operation mode %q", cfg.Mode)
361		}
362		if _, err := validation.ValidateMappings(cfg.Mappings); err != nil {
363			return nil, err
364		}
365		if cfg.Mode == modeReplicate && cfg.Force {
366			return nil, fmt.Errorf("replicate does not support --force; use sync instead")
367		}
368	
369		s := &syncSession{
370			cfg:             cfg,
371			stats:           newStats(cfg.ShowStats),
372			measurementDone: startMeasurement(cfg.MeasureMemory),
373		}
374		if cfg.Verbose {
375			s.logger = slog.New(slog.NewTextHandler(os.Stderr, &slog.HandlerOptions{
376				Level: slog.LevelInfo,
377			}))
378		}
379	
380		s.sourceConn, err = newConn(cfg.Source, "source", s.stats, cfg.HTTPClient)
381		if err != nil {
382			return nil, fmt.Errorf("create source transport: %w", err)
383		}
384	
385		refPrefixes := planner.RefPrefixes(cfg.Mappings, cfg.IncludeTags)
386		sourceRefs, sourceService, err := gitproto.ListSourceRefs(ctx, s.sourceConn, cfg.ProtocolMode, refPrefixes)
387		if err != nil {
388			return nil, fmt.Errorf("list source refs: %w", err)
389		}
390		sourceService.Verbose = cfg.Verbose
391		s.sourceService = sourceService
392		s.sourceRefMap = gitproto.RefHashMap(sourceRefs)
393	
394		if needTarget {
395			targetConn, err := newConn(cfg.Target, "target", s.stats, cfg.HTTPClient)
396			if err != nil {
397				return nil, fmt.Errorf("create target transport: %w", err)
398			}
399			targetAdv, err := gitproto.AdvertisedRefsV1(ctx, targetConn, transport.ReceivePackService)
400			if err != nil {
401				return nil, fmt.Errorf("list target refs: %w", err)
402			}
