408			targetFeatures := gitproto.TargetFeaturesFromAdvRefs(targetAdv)
409			s.target = &targetSession{
410				conn:     targetConn,
411				adv:      targetAdv,
412				refMap:   targetRefMap,
413				features: targetFeatures,
414				policy: planner.RelayTargetPolicy{
415					CapabilitiesKnown: targetFeatures.Known,
416					NoThin:            targetFeatures.NoThin,
417				},
418				pusher: gitproto.NewPusher(targetConn, targetAdv, cfg.Verbose),
419			}
420		}
421	
422		return s, nil
423	}
