	if err != nil {
		return nil, "", err
	}
	data, err := PostRPC(ctx, conn, transport.UploadPackService, body, true, "upload-pack ls-refs")
	if err != nil {
		return nil, "", err
	}
	return decodeV2LSRefs(bytes.NewReader(data))
}

