	out := make([]plannedBatch, 0, len(ordered))

	// planStopSet and planHaves accumulate across every planned branch so
	// that each new branch's commit-graph fetch and first-parent walk skip
	// history already covered by any previously planned branch. Trunk
	// (planned first via orderTrunkFirst when HEAD is known) typically
	// contributes the bulk of the set, but orphan chains such as
	// entire/checkpoints/v1 → v2 also share history only with each other,
	// not with trunk — accumulating across the whole run covers both shapes.
	planStopSet := map[plumbing.Hash]struct{}{}
	var planHaves []plumbing.Hash

	for _, ref := range ordered {
