	// history with each other, so haves don't help the *source*, but the
	// test asserts the structural accumulation: the k-th non-subsumed branch
	// must receive haves of length k, and its tip is folded into the set for
	// later branches.
	mainRef := plumbing.NewBranchReferenceName("main")
	aRef := plumbing.NewBranchReferenceName("orphan-a")
	bRef := plumbing.NewBranchReferenceName("orphan-b")

	mkTip := func(msg string) plumbing.Hash {
		t.Helper()
		store := memory.NewStorage()
		obj := store.NewEncodedObject()
		commit := &object.Commit{
			Author:    object.Signature{Name: "t", Email: "t@e", When: time.Unix(1, 0).UTC()},
			Committer: object.Signature{Name: "t", Email: "t@e", When: time.Unix(1, 0).UTC()},
			Message:   msg,
			TreeHash:  plumbing.ZeroHash,
		}
		if err := commit.Encode(obj); err != nil {
			t.Fatalf("encode %s: %v", msg, err)
		}
		h, err := store.SetEncodedObject(obj)
		if err != nil {
			t.Fatalf("store %s: %v", msg, err)
		}
		return h
	}
	mainHash := mkTip("main-tip")
	aHash := mkTip("orphan-a-tip")
	bHash := mkTip("orphan-b-tip")

	type call struct {
		ref   plumbing.ReferenceName
		haves []plumbing.Hash
	}
	var calls []call

	_, err := Execute(context.Background(), Params{
		SourceService: fakeBootstrapSource{
			fetchCommitGraph: func(_ context.Context, store storer.Storer, _ *gitproto.Conn, ref gitproto.DesiredRef, haves []plumbing.Hash) error {
				calls = append(calls, call{ref: ref.SourceRef, haves: append([]plumbing.Hash(nil), haves...)})
				// Write a matching isolated commit so the first-parent walk
				// finds something at ref.SourceHash.
				var msg string
				switch ref.SourceRef {
				case mainRef:
					msg = "main-tip"
				case aRef:
					msg = "orphan-a-tip"
				case bRef:
					msg = "orphan-b-tip"
				default:
					t.Fatalf("unexpected ref %s", ref.SourceRef)
				}
				obj := store.NewEncodedObject()
				commit := &object.Commit{
					Author:    object.Signature{Name: "t", Email: "t@e", When: time.Unix(1, 0).UTC()},
					Committer: object.Signature{Name: "t", Email: "t@e", When: time.Unix(1, 0).UTC()},
					Message:   msg,
					TreeHash:  plumbing.ZeroHash,
				}
				if err := commit.Encode(obj); err != nil {
					return err
				}
				_, err := store.SetEncodedObject(obj)
				return err
			},
			fetchPack: func(_ context.Context, _ *gitproto.Conn, _ map[plumbing.ReferenceName]gitproto.DesiredRef, _ map[plumbing.ReferenceName]plumbing.Hash) (io.ReadCloser, error) {
				return io.NopCloser(bytes.NewReader([]byte("PACK"))), nil
			},
		},
		TargetPusher: fakeBootstrapPusher{
			pushPack: func(_ context.Context, _ []gitproto.PushCommand, pack io.ReadCloser) error {
				_ = pack.Close()
				return nil
			},
			pushCommands: func(_ context.Context, _ []gitproto.PushCommand) error { return nil },
		},
		DesiredRefs: map[plumbing.ReferenceName]planner.DesiredRef{
			mainRef: {SourceRef: mainRef, TargetRef: mainRef, SourceHash: mainHash, Kind: planner.RefKindBranch, Label: "main"},
			aRef:    {SourceRef: aRef, TargetRef: aRef, SourceHash: aHash, Kind: planner.RefKindBranch, Label: "orphan-a"},
			bRef:    {SourceRef: bRef, TargetRef: bRef, SourceHash: bHash, Kind: planner.RefKindBranch, Label: "orphan-b"},
		},
		TargetRefs:       map[plumbing.ReferenceName]plumbing.Hash{},
		SourceHeadTarget: mainRef,
		TargetMaxPack:    1024 * 1024,
	}, "empty target")
	if err != nil {
		t.Fatalf("Execute: %v", err)
	}

	if len(calls) != 3 {
		t.Fatalf("expected 3 commit-graph fetches, got %d", len(calls))
	}
	// Trunk (main) first, no haves.
	if calls[0].ref != mainRef {
		t.Errorf("calls[0].ref = %s, want main", calls[0].ref)
	}
	if len(calls[0].haves) != 0 {
		t.Errorf("calls[0].haves = %v, want empty (trunk)", calls[0].haves)
	}
	// Remaining branches sort alphabetically: orphan-a, then orphan-b.
	if calls[1].ref != aRef {
		t.Errorf("calls[1].ref = %s, want orphan-a", calls[1].ref)
	}
	if len(calls[1].haves) != 1 || calls[1].haves[0] != mainHash {
		t.Errorf("calls[1].haves = %v, want [mainHash=%s]", calls[1].haves, mainHash)
	}
	if calls[2].ref != bRef {
		t.Errorf("calls[2].ref = %s, want orphan-b", calls[2].ref)
	}
	// Third call accumulates both previous tips.
	if len(calls[2].haves) != 2 {
		t.Fatalf("calls[2].haves len = %d, want 2", len(calls[2].haves))
	}
	got := map[plumbing.Hash]bool{}
	for _, h := range calls[2].haves {
		got[h] = true
	}
	if !got[mainHash] || !got[aHash] {
		t.Errorf("calls[2].haves = %v, want to contain mainHash=%s and aHash=%s", calls[2].haves, mainHash, aHash)
	}
}

func TestExecuteBatchedSubsumedBranchSkipsPack(t *testing.T) {

input.old_string:
for _, batch := range batches {
	if batch.subsumed {
		cmds := []gitproto.PushCommand{{
			Name: batch.Plan.TargetRef,
			Old:  plumbing.ZeroHash,
			New:  batch.Plan.SourceHash,
		}}
		if err := p.TargetPusher.PushCommands(ctx, cmds); err != nil {
			return result, fmt.Errorf("create subsumed branch ref for %s: %w", batch.Plan.TargetRef, err)
		}
		completedRefs[batch.Plan.TargetRef] = batch.Plan.SourceHash
		result.BatchCount++
		p.log("bootstrap batch subsumed branch finalized",
			"branch", batch.Plan.TargetRef.String(),
			"source_hash", planner.ShortHash(batch.Plan.SourceHash))
		continue
	}

input.new_string:
for _, batch := range batches {
	if batch.subsumed {
		cmds := []gitproto.PushCommand{{
			Name: batch.Plan.TargetRef,
			Old:  plumbing.ZeroHash,
			New:  batch.Plan.SourceHash,
		}}
		// A prior interrupted run may have written this branch's bootstrap
		// temp ref before the branch became subsumed. The non-subsumed
		// path normally cleans it up (stale-temp recovery near the top of
		// this loop, plus the final delete after cutover); the subsumed
		// path bypasses both, so we must include the delete here or the
		// temp ref persists indefinitely on the target.
		if !batch.ResumeHash.IsZero() {
			result.TempRefs = append(result.TempRefs, batch.TempRef.String())
			cmds = append(cmds, gitproto.PushCommand{
				Name:   batch.TempRef,
				Old:    batch.ResumeHash,
				Delete: true,
			})
		}
		if err := p.TargetPusher.PushCommands(ctx, cmds); err != nil {
			return result, fmt.Errorf("finalize subsumed branch %s: %w", batch.Plan.TargetRef, err)
		}
		completedRefs[batch.Plan.TargetRef] = batch.Plan.SourceHash
		result.BatchCount++
		p.log("bootstrap batch subsumed branch finalized",
			"branch", batch.Plan.TargetRef.String(),
			"source_hash", planner.ShortHash(batch.Plan.SourceHash),
			"cleaned_temp_ref", !batch.ResumeHash.IsZero())
		continue
	}

input.old_string:
if _, subsumed := planStopSet[ref.SourceHash]; subsumed {
	p.log("bootstrap batch branch subsumed",
		"branch", ref.TargetRef.String(),
		"source_hash", planner.ShortHash(ref.SourceHash))
	out = append(out, plannedBatch{
		BootstrapBatch: planner.BootstrapBatch{
			Plan: planner.BranchPlan{
				Branch: ref.Label, SourceRef: ref.SourceRef,
				TargetRef: ref.TargetRef, SourceHash: ref.SourceHash,
				Kind: ref.Kind, Action: planner.ActionCreate,
			},
		},
		subsumed: true,
	})
	continue
}

input.new_string:
if _, subsumed := planStopSet[ref.SourceHash]; subsumed {
	tempRef := planner.BootstrapTempRef(ref.TargetRef)
	p.log("bootstrap batch branch subsumed",
		"branch", ref.TargetRef.String(),
		"source_hash", planner.ShortHash(ref.SourceHash))
	// Carry TempRef and the current target-side hash for that temp
	// ref so the executor can clean up a stale ref left behind by an
	// earlier interrupted run before the branch became subsumed.
	out = append(out, plannedBatch{
		BootstrapBatch: planner.BootstrapBatch{
			Plan: planner.BranchPlan{
				Branch: ref.Label, SourceRef: ref.SourceRef,
				TargetRef: ref.TargetRef, SourceHash: ref.SourceHash,
				Kind: ref.Kind, Action: planner.ActionCreate,
			},
			TempRef:    tempRef,
			ResumeHash: p.TargetRefs[tempRef],
		},
		subsumed: true,
	})
	continue
}

func TestExecuteBatchedSubsumedBranchDeletesStaleTempRef(t *testing.T) {
	// Regression: an interrupted prior bootstrap can leave
	// refs/gitsync/bootstrap/heads/<branch> on the target. If a later run
	// classifies that branch as subsumed (its tip is now reachable from
	// trunk), the subsumed-only push path must still delete the stale temp
	// ref or it persists indefinitely.
	mainRef := plumbing.NewBranchReferenceName("main")
	featureRef := plumbing.NewBranchReferenceName("feature")
	hashes := makeLinearCommitChain(t, 3)
	mainHash := hashes[2]
	featureHash := hashes[0] // subsumed by main
	staleTempHash := plumbing.NewHash("dddddddddddddddddddddddddddddddddddddddd")
	tempRef := planner.BootstrapTempRef(featureRef)

	var pushCommandsBatches [][]gitproto.PushCommand
	result, err := Execute(context.Background(), Params{
		SourceService: fakeBootstrapSource{
			fetchCommitGraph: func(_ context.Context, store storer.Storer, _ *gitproto.Conn, _ gitproto.DesiredRef, _ []plumbing.Hash) error {
				writeLinearCommitChain(t, store, 3)
				return nil
			},
			fetchPack: func(_ context.Context, _ *gitproto.Conn, _ map[plumbing.ReferenceName]gitproto.DesiredRef, _ map[plumbing.ReferenceName]plumbing.Hash) (io.ReadCloser, error) {
				return io.NopCloser(bytes.NewReader([]byte("PACK"))), nil
			},
		},
		TargetPusher: fakeBootstrapPusher{
			pushPack: func(_ context.Context, _ []gitproto.PushCommand, pack io.ReadCloser) error {
				_ = pack.Close()
				return nil
			},
			pushCommands: func(_ context.Context, cmds []gitproto.PushCommand) error {
				pushCommandsBatches = append(pushCommandsBatches, append([]gitproto.PushCommand(nil), cmds...))
				return nil
			},
		},
		DesiredRefs: map[plumbing.ReferenceName]planner.DesiredRef{
			mainRef:    {SourceRef: mainRef, TargetRef: mainRef, SourceHash: mainHash, Kind: planner.RefKindBranch, Label: "main"},
			featureRef: {SourceRef: featureRef, TargetRef: featureRef, SourceHash: featureHash, Kind: planner.RefKindBranch, Label: "feature"},
		},
		TargetRefs: map[plumbing.ReferenceName]plumbing.Hash{
			tempRef: staleTempHash,
		},
		SourceHeadTarget: mainRef,
		TargetMaxPack:    1024 * 1024,
	}, "empty target")
	if err != nil {
		t.Fatalf("Execute: %v", err)
	}

	var foundCreate, foundDelete bool
	for _, cmds := range pushCommandsBatches {
		// The subsumed branch must finalize in a single push containing both
		// commands so a partial failure can't leave the target with the new
		// real ref but the stale temp ref still hanging around.
		hasCreate, hasDelete := false, false
		for _, cmd := range cmds {
			if cmd.Name == featureRef && cmd.New == featureHash && cmd.Old.IsZero() && !cmd.Delete {
				hasCreate = true
			}
			if cmd.Name == tempRef && cmd.Delete && cmd.Old == staleTempHash {
				hasDelete = true
			}
		}
		if hasCreate && hasDelete {
			foundCreate, foundDelete = true, true
			break
		}
	}
	if !foundCreate || !foundDelete {
		t.Fatalf("expected a single PushCommands containing both create %s and delete %s; got %v",
			featureRef, tempRef, pushCommandsBatches)
	}

	var sawTempRef bool
	for _, name := range result.TempRefs {
		if name == tempRef.String() {
			sawTempRef = true
		}
	}
	if !sawTempRef {
		t.Errorf("result.TempRefs missing %s; got %v", tempRef, result.TempRefs)
	}
}

